import { Item } from '#utils/UNSAFE_dataProvider';
import { error } from '#utils/UNSAFE_logger';
import { ItemTextFunctionType, ItemTextType } from '#utils/UNSAFE_selectUtils';

export type ComponentName = 'InlineSelectSingle' | 'SelectSingle' | 'SelectMultiple';

export function renderItemText<K, D>(
  item: Item<K, D>,
  itemText: ItemTextType<K, D>,
  componentName: ComponentName
) {
  // if item-text is a string and the data has the specified field, return it;
  // otherwise log an error
  if (typeof itemText === 'string') {
    if (Object.prototype.hasOwnProperty.call(item.data, itemText)) {
      const retData = item.data[itemText];
      return String(retData);
    }
    error(`${componentName}: itemText specifies field that does not exist: ${itemText}`);
    // return undefined if the field doesn't exist
    return undefined;
  }
  // if item-text is a function, call it to create a display label
  return (itemText as ItemTextFunctionType<K, D>)(item);
}
